  1	import React from 'react';
  2	
  3	import AlertsCardAccordionItem from '@kubevirt-utils/components/AlertsCard/AlertsCardAccordionItem';
  4	import { AlertType, SimplifiedAlerts } from '@kubevirt-utils/components/AlertsCard/utils/types';
  5	import {
  6	  labelColor,
  7	  labelIcon,
  8	  labelText,
  9	} from '@kubevirt-utils/components/AlertsCard/utils/utils';
 10	import { isEmpty } from '@kubevirt-utils/utils/utils';
 11	import {
 12	  Accordion,
 13	  AccordionContent,
 14	  AccordionItem,
 15	  AccordionToggle,
 16	  Button,
 17	  ButtonVariant,
 18	  Flex,
 19	  Label,
 20	} from '@patternfly/react-core';
 21	
 22	type AlertsDrawerProps = {
 23	  sortedAlerts: SimplifiedAlerts;
 24	};
 25	
 26	const AlertsDrawer: React.FC<AlertsDrawerProps> = ({ sortedAlerts }) => {
 27	  const [alertTypeOpen, setAlertTypeOpen] = React.useState<AlertType>(null);
 28	
 29	  const [titleOpen, setTitleOpen] = React.useState<boolean>(false);
 30	  const [defaultOpenCritical, setDefaultOpenCritical] = React.useState<boolean>(false);
 31	
 32	  const handleDrawerToggleClick = React.useCallback((alertType: AlertType): void => {
 33	    setAlertTypeOpen((alert) => (alert === alertType ? null : alertType));
 34	  }, []);
 35	  const alertsQuantity =
 36	    Object.values(sortedAlerts)?.reduce((acc, category) => acc + category?.length, 0) || 0;
 37	
 38	  React.useEffect(() => {
 39	    //open critical alerts by default, if exists, only for the first time loading
 40	    if (!defaultOpenCritical && !isEmpty(sortedAlerts?.critical)) {
 41	      setTitleOpen(true);
 42	      setAlertTypeOpen(AlertType.critical);
 43	      setDefaultOpenCritical(true);
 44	    }
 45	  }, [sortedAlerts, defaultOpenCritical]);
 46	
 47	  return (
 48	    <div className="alerts-card__drawer">
 49	      {alertsQuantity > 0 ? (
 50	        <Accordion asDefinitionList isBordered>
 51	          <AccordionItem>
 52	            <AccordionToggle
 53	              onClick={() => {
 54	                setTitleOpen((title) => {
 55	                  title && setAlertTypeOpen(null);
 56	                  return !title;
 57	                });
 58	              }}
 59	              className="alerts-card__toggle--main"
 60	              id="toggle-main"
 61	
 62	            >
 63	              <Flex>
 64	                {Object.keys(sortedAlerts)?.map((alertType) => {
 65	                  const numAlerts = sortedAlerts?.[alertType]?.length;
 66	                  // // Don't show alerts in the drawer header if there are no alerts of the type
 67	                  if (numAlerts === 0) {
 68	                    return null;
 69	                  }
 70	                  return (
 71	                    <Button
 72	                      onClick={(e) => {
 73	                        setAlertTypeOpen((prevAlertOpen) =>
 74	                          titleOpen && prevAlertOpen === alertType
 75	                            ? null
 76	                            : (alertType as AlertType),
 77	                        );
 78	                        setTitleOpen(
 79	                          (prevTitleOpen) => !prevTitleOpen || alertTypeOpen !== alertType,
 80	                        );
 81	                        e?.stopPropagation();
 82	                      }}
 83	                      className="pf-m-link--align-left"
 84	                      key={alertType}
 85	                      variant={ButtonVariant.plain}
 86	                    >
 87	                      <Label
 88	                        className="alerts-label"
 89	                        color={labelColor[alertType]}
 90	                        icon={labelIcon[alertType]}
 91	                        key={alertType}
 92	                      >
 93	                        {numAlerts || 0}
 94	                      </Label>
 95	                      <span className="alerts-label--text">{labelText[alertType]}</span>
 96	                    </Button>
 97	                  );
 98	                })}
 99	              </Flex>
100	            </AccordionToggle>
101	            <AccordionContent id="toggle-main">
102	              {Object.entries(sortedAlerts)?.map(([alertType, alerts]) => (
103	                <AlertsCardAccordionItem
104	                  alertOpen={alertTypeOpen}
105	                  alerts={alerts}
106	                  alertType={AlertType[alertType]}
107	                  handleDrawerToggleClick={handleDrawerToggleClick}
108	                  key={alertType}
109	                />
110	              ))}
111	            </AccordionContent>
112	          </AccordionItem>
113	        </Accordion>
114	      ) : null}
115	    </div>
116	  );
117	};
118	
119	export default AlertsDrawer;

